import React, { createContext, useContext, useState, useEffect } from "react";

const AuthContext = createContext(null); // Initialize with null for clarity

export function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true); // Add loading state

  // Load user from localStorage on mount and set loading to false
  useEffect(() => {
    const loadUser = () => {
      try {
        const storedUser = localStorage.getItem("user");
        if (storedUser) {
          setUser(JSON.parse(storedUser));
        }
      } catch (error) {
        console.error("Failed to parse user from localStorage", error);
        // Clear any malformed user data if parsing fails
        localStorage.removeItem("user");
      } finally {
        setLoading(false); // Always set loading to false after attempting to load user
      }
    };
    loadUser();
  }, []); // Empty dependency array means this runs once on mount

  /**
   * Logs in a user. This function should typically make an API call.
   * For now, it simulates a successful login after a delay.
   *
   * @param {string} email The user's email.
   * @param {string} password The user's password.
   * @returns {Promise<object>} A promise that resolves with user data on success.
   * @throws {Error} Throws an error if login fails (e.g., invalid credentials).
   */
  const login = async (email, password) => {
    setLoading(true); // Indicate that a login attempt is in progress
    try {
      // --- Simulate API call for authentication ---
      // In a real application, you would replace this with an actual fetch or axios call:
      // const response = await fetch('/api/login', {
      //   method: 'POST',
      //   headers: { 'Content-Type': 'application/json' },
      //   body: JSON.stringify({ email, password })
      // });
      // if (!response.ok) {
      //   const errorData = await response.json();
      //   throw new Error(errorData.message || 'Login failed');
      // }
      // const userData = await response.json();

      // For demonstration:
      await new Promise((resolve) => setTimeout(resolve, 1000)); // Simulate network delay

      if (email === "test@example.com" && password === "password") {
        const userData = {
          id: "123",
          name: "Demo User",
          email: email,
          token: "fake-jwt-token-for-demo", // In real app, store an actual token
        };
        setUser(userData);
        localStorage.setItem("user", JSON.stringify(userData));
        return userData; // Return user data on success
      } else {
        throw new Error("Invalid email or password");
      }
    } catch (error) {
      console.error("Login Error:", error);
      // It's important to clear user and token on failed login attempts
      // in case of partial or corrupted state.
      setUser(null);
      localStorage.removeItem("user");
      throw error; // Re-throw the error so components can handle it
    } finally {
      setLoading(false); // Always set loading to false after login attempt
    }
  };

  // Logout → clear user + remove from storage
  const logout = () => {
    setLoading(true); // Optionally set loading during logout if it's async
    setUser(null);
    localStorage.removeItem("user");
    // Optionally, if your logout requires an API call:
    // try { await fetch('/api/logout'); } catch (e) { console.error("Logout API failed", e); }
    setLoading(false);
  };

  const authContextValue = {
    user,
    loading, // Provide loading state
    login,
    logout,
  };

  return (
    <AuthContext.Provider value={authContextValue}>
      {children}
    </AuthContext.Provider>
  );
}

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error("useAuth must be used within an AuthProvider");
  }
  return context;
};
